mapper.select:
SELECT bl.id, bl.display_name AS displayName, bl.event_type AS eventType, bl.event_time AS eventTime, bl.face_image_url AS faceImageUrl, bl.body_image_url AS bodyImageUrl, bl.location_id AS locationId, l.name AS locationName, bl.person_id AS personId, bl.track_key AS trackKey, bl.session_id AS sessionId, bl.person_kind AS personKind, bl.source, bl.face_match_score AS faceMatchScore, bl.body_match_score AS bodyMatchScore, bl.quality_flag AS qualityFlag, bl.scene_group_id AS sceneGroupId, bl.clip_id AS clipId, bl.analysis_status AS analysisStatus, bl.created_at AS createdAt FROM behavior_logs bl LEFT JOIN locations l ON l.id = bl.location_id
bl.event_time >= #{statDate}::date AND bl.event_time < (#{statDate}::date + INTERVAL '1 day')
AND bl.location_id = #{locationId}
AND bl.event_type = #{eventType}
ORDER BY bl.event_time DESC, bl.id DESC
LIMIT #{limit}

SELECT COUNT(1)
FROM behavior_logs
WHERE track_key = #{trackKey}
  AND event_type = #{eventType}
  AND event_time = #{eventTime}
  AND source = #{source}

mapper.update:
UPDATE behavior_logs
SET face_image_url = #{faceImageUrl},
    body_image_url = #{bodyImageUrl}
WHERE id = #{id}
